      function CF_TITEMPRESAFormula return VARCHAR2 is

   vTitEmpresa varchar2(80);
   vTexto      varchar2(80);

begin
   select tit_reportes 
   into   vTitEmpresa
   from   empresa
   where  cod_empresa = :pg_cOD_EMPRESA;

   return  upper(vTitEmpresa);
exception

   when SRW.NO_DATA_FOUND then

      select texto
      into   vTexto
      from   mensajes_sistema
      where  num_mensaje  = '000046'
        and  cod_sistema  = 'PA'
        and  cod_idioma   = :pg_coD_IDIOMA;

        SRW.message(0, 'PA-000046 ' || vTexto);
        raise SRW.program_abort;

end;

      function CF_TitAgenciaFormula return VARCHAR2 is

   vTitAgencia varchar2(80);
   vTexto      varchar2(80);

begin

   select descripcion
   into   vTitAgencia
   from   agencia
   where  cod_empresa = :pg_COD_EMPRESA
     and  cod_agencia = :pg_COD_AGENCIA;

   return upper(vTitAgencia); 

exception

   when SRW.NO_DATA_FOUND then

      select texto
      into   vTexto
      from   mensajes_sistema
      where  num_mensaje  = '000045'
        and  cod_sistema  = 'PA'
        and  cod_idioma   = :pg_COD_IDIOMA;

        SRW.message(0, 'PA-000045 ' || vTexto);
        raise SRW.program_abort;
end;

      function CF_TitSistemaFormula return VARCHAR2 is
   vTitSistema varchar2(80);
   vTexto      varchar2(80);
begin
   select  titulo
   into    vTitSistema
   from    titulos_sistemas
   where   cod_sistema = :pg_COD_SISTEMA
     and   cod_idioma  = :pg_COD_IDIOMA;

   return upper(vTitSistema);

exception

   when SRW.NO_DATA_FOUND then

      select texto
      into   vTexto
      from   mensajes_sistema
      where  num_mensaje  = '000048'
        and  cod_sistema  = 'PA'
        and  cod_idioma   = :pg_COD_IDIOMA;

        SRW.message(0, 'PA-000048 ' || vTexto);
        raise SRW.program_abort;

end;

      function CF_TitReporteFormula return VARCHAR2 is
   vTitReporte varchar2(80);
   vTexto      varchar2(80);

begin
   select titulo
   into   vTitReporte
   from   titulos_reportes
   where  nom_reporte = :pg_NOM_REPORTE
     and  cod_idioma  = :pg_COD_IDIOMA;

   return vTitReporte;

exception

   when SRW.NO_DATA_FOUND then

      select texto
      into   vTexto
      from   mensajes_sistema
      where  num_mensaje  = '000047'
        and  cod_sistema  = 'PA'
        and  cod_idioma   = :pg_COD_IDIOMA;

        SRW.message(0, 'PA-000047 ' || vTexto);
        raise SRW.program_abort;

end;

      function NOMREPORTEValidTrigger return boolean is
begin
  return (TRUE);
end;

      function CF_total_directoFormula return Number is
  v_total_dir   number(18,2);
begin

  v_total_dir := nvl(:cs_tot_dir_bl1,0) + nvl(:cs_tot_dir_fl,0) + nvl(:cs_tot_dir_ind,0);
  return v_total_dir;
end;

      function CF_total_contingenteFormula return Number is
  v_total_ind   number(18,2);
begin

  v_total_ind := nvl(:cs_tot_cont_bl1,0) + nvl(:cs_tot_cont_fl,0) + nvl(:cs_tot_cont_ind,0);
  return v_total_ind;
end;

      function M_2FormatTrigger return boolean is
begin
  if nvl(:cs_tot_dir_bl1,0) > 0 or nvl(:cs_tot_cont_bl1,0) > 0 then
