      function Cf_califFormula return Char is
 v_calif varchar2(3);
begin
  --v_calif := pr_calif_automatica.Obt_Calif_X_Cliente('1',:p_cod_cliente);
   BEGIN
	  SELECT cod_calif
	   into v_calif
	  FROM PR_CALIF_X_CLIENTE a
	  WHERE a.cod_empresa = :pg_cOD_EMPRESA
	    and a.cod_persona = :p_cod_cliente
		  AND a.fec_calif IN (SELECT  MAX(b.fec_calif)
                            FROM PR_CALIF_X_CLIENTE b
                     		    WHERE b.cod_empresa = :pg_cOD_EMPRESA
                        		  AND b.cod_persona = a.cod_persona);
  EXCEPTION
  	WHEN NO_DATA_FOUND THEN
  	  v_calif := 'A';
  END;

  return(v_calif);
end;

      function CF_TipocambioFormula return Number is
   v_tipcamb number(16,2);
   v_mensaje varchar2(100);
begin
    begin
		    Cg_Utl.Obtiene_TC_Conta(1, :sysdate, v_tipcamb, v_mensaje);
    exception
        when others then
          v_tipcamb := null;
    end;
    return v_tipcamb;
end;
